insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Bodo Okhrang', 'development', 'A.I. Tool — Web Development', 'assets/projects/1.webp', 'An <strong>AI-powered Anglo-Bodo dictionary</strong> and language platform built for the Bodo community. Instant word lookup, smart suggestions and a clean reading experience — now serving <strong>50,000+ visitors every month</strong> and growing.', 'Full-stack Developer', 'PHP · MySQL · JS · AI', '2024 — live', 'visit live site', 'https://bodookhrang.com', null, null, 0);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('FlopShop', 'development', 'E-commerce — PWA', 'assets/projects/12.webp', 'A modern <strong>e-commerce progressive web app</strong> — installable, offline-friendly and fast on any device. Snappy product browsing, cart flow and a checkout experience that feels native.', 'Designer & Developer', 'React · PWA · Vercel', '2025 — live', 'visit live site', 'https://flopshop.vercel.app', null, null, 1);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('CrewSpace AI', 'development', 'A.I. Tool — Browser Extension', 'assets/projects/11.webp', 'A <strong>browser extension</strong> that brings AI assistance straight into your workspace — summarise, draft and organise without ever leaving the tab you are working in.', 'Creator & Developer', 'JS · Extension APIs · AI', '2025 — live', 'visit live site', 'https://crewspace-ai.vercel.app', null, null, 2);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Kokrajhar University', 'development', 'Education — Web & App', 'assets/projects/2.webp', 'The digital front door for <strong>Kokrajhar University</strong> — a website and companion app giving students notices, resources and campus information in one organised, mobile-first place.', 'Web & App Developer', 'PHP · MySQL · React Native', '2024 — live', 'visit live site', 'https://ku-app.in', null, null, 3);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Swrzee Enterprise', 'development', 'Enterprise — Web Development', 'assets/projects/3.webp', 'A clean, credible <strong>business website</strong> for Swrzee Enterprise — product showcase, company story and contact flows designed to convert visitors into customers.', 'Designer & Developer', 'PHP · CSS · JS', '2024 — live', 'visit live site', 'https://swrzee.in', null, null, 4);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Trip to Darjeeling', 'video', 'Travel Film — Video Editing', 'assets/projects/4.webp', 'A <strong>cinematic travel film</strong> through the hills of Darjeeling — tea gardens, toy trains and misty ridgelines, cut to rhythm with colour grading that keeps the mountain mood intact.', 'Editor & Colorist', 'Premiere · DaVinci', '2024', 'watch the film', 'https://www.youtube.com/watch?v=gNVz83QSoY4', null, null, 5);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Andaman & Nicobar Islands', 'video', 'Travel Film — Video Editing', 'assets/projects/5.webp', 'Island hopping, turquoise water and slow sunsets — a <strong>travel edit</strong> built around pacing: fast cuts on the boats, long breaths on the beaches.', 'Editor & Colorist', 'Premiere · DaVinci', '2024', 'watch the film', 'https://www.youtube.com/watch?v=gBvocwLObFQ', null, null, 6);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Google Dev Group — 2025', 'video', 'Event — Video Editing', 'assets/projects/6.webp', 'Official <strong>aftermovie for the Google Developer Group 2025</strong> event — talks, crowd energy and behind-the-scenes moments compressed into a tight, high-energy recap.', 'Editor', 'Premiere · CapCut', '2025', 'watch the film', null, 'https://pub-fe9b85f97c6a4773bbf0ceb5f53c430b.r2.dev/GDG.mp4', null, 7);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Open Mic RGU — 2025', 'video', 'Event — Video Editing', 'assets/projects/7.webp', 'An <strong>event recap</strong> of Open Mic at RGU — raw performances, audience reactions and stage lights, edited to keep the live-room feeling on screen.', 'Editor', 'Premiere · CapCut', '2025', 'watch the film', null, 'https://pub-fe9b85f97c6a4773bbf0ceb5f53c430b.r2.dev/open-mic.mp4', null, 8);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('Badminton Tournament', 'design', 'Event — Banner Design', 'assets/projects/8.webp', 'A bold <strong>tournament banner</strong> — strong type hierarchy, action photography and a layout that reads clearly from across a hall or in a feed.', 'Designer', 'Figma · Canva', '2024', 'view the design', null, null, 'assets/projects/8.webp', 9);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('BODOअख्रां Pvt. Ltd. Logo', 'design', 'Brand — Logo Design', 'assets/projects/9.webp', 'Identity work for <strong>BODOअख्रां Pvt. Ltd.</strong> — a mark that blends Devanagari character with a modern wordmark, built to hold up from favicon to billboard.', 'Brand Designer', 'Figma · Krita', '2024', 'view the design', null, null, 'assets/projects/9.webp', 10);
insert into public.projects (title, cat, cat_label, img, description, role, stack, year, action, url, video, image, sort) values ('My Tea', 'design', 'Local Shop — Banner Design', 'assets/projects/10.webp', 'A warm, appetising <strong>storefront banner</strong> for a local tea shop — friendly type, rich colour and a layout that makes you want a cup immediately.', 'Designer', 'Canva · Krita', '2024', 'view the design', null, null, 'assets/projects/10.webp', 11);
